head.script:
scwin.hid_odrNo = "";
scwin.hid_repClntNo = "";
scwin.hid_clntNo = "";
scwin.hid_clntNm = "";
scwin.hid_mchtOdrKndCd = "";
scwin.hid_mchtOdrKndNm = "";
scwin.hid_mchtOdrNo = "";
scwin.hid_mcomOdrNo = "";
scwin.hid_logSeq = "";
scwin.hid_chkReterieve = "";
scwin.hid_frameLoad = "";
scwin.hid_orderCommodityCnt = "";
scwin.hid_odrDelYn = "";

scwin.tab1Url = "/ui/ds/tp/kpx/tp_801_01_04b.xml";
scwin.tab2Url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_40b.xml";
scwin.tab3Url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_24b.xml";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();

    let repClntNo = (scwin.params != null && scwin.params["repClntNo"] != null) ? scwin.params["repClntNo"] : "";
    let clntNo = (scwin.params != null && scwin.params["clntNo"] != null) ? scwin.params["clntNo"] : "";
    let clntNm = (scwin.params != null && scwin.params["clntNm"] != null) ? scwin.params["clntNm"] : "";
    let mchtOdrKndCd = (scwin.params != null && scwin.params["mchtOdrKndCd"] != null) ? scwin.params["mchtOdrKndCd"] : "";
    let mchtOdrKndNm = (scwin.params != null && scwin.params["mchtOdrKndNm"] != null) ? scwin.params["mchtOdrKndNm"] : "";
    let mchtOdrNo = (scwin.params != null && scwin.params["mchtOdrNo"] != null) ? scwin.params["mchtOdrNo"] : "";
    let mcomOdrNo = (scwin.params != null && scwin.params["mcomOdrNo"] != null) ? scwin.params["mcomOdrNo"] : "";
    let logSeq = (scwin.params != null && scwin.params["logSeq"] != null) ? scwin.params["logSeq"] : "";
    let type = (scwin.params != null && scwin.params["type"] != null) ? scwin.params["type"] : "";

    scwin.hid_odrNo = mcomOdrNo;
    scwin.hid_repClntNo = repClntNo;
    scwin.hid_clntNo = clntNo;
    scwin.hid_clntNm = clntNm;
    scwin.hid_mchtOdrKndCd = mchtOdrKndCd;
    scwin.hid_mchtOdrKndNm = mchtOdrKndNm;
    scwin.hid_mchtOdrNo = mchtOdrNo;
    scwin.hid_mcomOdrNo = mcomOdrNo;
    scwin.hid_logSeq = logSeq;
    scwin.hid_chkReterieve = type;

    dma_search.set("repClntNo", repClntNo);
    dma_search.set("clntNo", clntNo);
    dma_search.set("clntNm", clntNm);
    dma_search.set("mchtOdrKndCd", mchtOdrKndCd);
    dma_search.set("mchtOdrKndNm", mchtOdrKndNm);
    dma_search.set("mchtOdrNo", mchtOdrNo);
    dma_search.set("mcomOdrNo", mcomOdrNo);
    dma_search.set("logSeq", logSeq);
    dma_search.set("type", type);

    scwin.f_initSearchFields();

    if (scwin.hid_chkReterieve == "retrieve") {
        scwin.f_Retrieve();
    }
};

scwin.onUdcCompleted = function() {
};

scwin.f_initSearchFields = function() {
    if (!$c.gus.cfIsNull(scwin.hid_mcomOdrNo)) {
        ed_input2.setValue(scwin.hid_mcomOdrNo);
    }
    if (!$c.gus.cfIsNull(scwin.hid_mchtOdrNo)) {
        ed_input1.setValue(scwin.hid_mchtOdrNo);
    }
};

scwin.f_Retrieve = async function() {
    if ($c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
        scwin.hid_odrNo = scwin.hid_mcomOdrNo;
    }
    if ($c.gus.cfIsNull(scwin.hid_clntNo.trim())) {
        scwin.hid_clntNo = (scwin.params != null && scwin.params["clntNo"] != null) ? scwin.params["clntNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrKndCd.trim())) {
        scwin.hid_mchtOdrKndCd = (scwin.params != null && scwin.params["mchtOdrKndCd"] != null) ? scwin.params["mchtOdrKndCd"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrNo.trim())) {
        scwin.hid_mchtOdrNo = (scwin.params != null && scwin.params["mchtOdrNo"] != null) ? scwin.params["mchtOdrNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mcomOdrNo.trim())) {
        scwin.hid_mcomOdrNo = (scwin.params != null && scwin.params["mcomOdrNo"] != null) ? scwin.params["mcomOdrNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_logSeq.trim())) {
        scwin.hid_logSeq = (scwin.params != null && scwin.params["logSeq"] != null) ? scwin.params["logSeq"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_chkReterieve.trim())) {
        scwin.hid_chkReterieve = (scwin.params != null && scwin.params["type"] != null) ? scwin.params["type"] : "";
    }

    dma_search.set("repClntNo", scwin.hid_repClntNo);
    dma_search.set("clntNo", scwin.hid_clntNo);
    dma_search.set("clntNm", scwin.hid_clntNm);
    dma_search.set("mchtOdrKndCd", scwin.hid_mchtOdrKndCd);
    dma_search.set("mchtOdrKndNm", scwin.hid_mchtOdrKndNm);
    dma_search.set("mchtOdrNo", scwin.hid_mchtOdrNo);
    dma_search.set("mcomOdrNo", scwin.hid_mcomOdrNo);
    dma_search.set("logSeq", scwin.hid_logSeq);
    dma_search.set("type", scwin.hid_chkReterieve);

    await $c.sbm.execute(sbm_Retrieve);
};

scwin.sbm_Retrieve_submitdone = async function(e) {
    if (ds_mchtOdrKndCd.getRowCount() > 0) {
        scwin.f_setMchtOdrKndCombo();
    } else {
        ds_mchtOdrKndCd.insertRow(0);
        ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
        ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.hid_mchtOdrKndNm);
        scwin.f_setMchtOdrKndCombo();
    }

    if (ds_shipmentIndicationOrder.getRowCount() > 0) {
        scwin.f_setLogSeqCombo();
    }

    scwin.f_setOrderInfoToUI();

    scwin.hid_chkReterieve = "retrieveIn";
};

scwin.sbm_Retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_setMchtOdrKndCombo = function() {
    // TODO: acb_autoComplete1에 ds_mchtOdrKndCd 데이터 바인딩
};

scwin.f_setLogSeqCombo = function() {
    // TODO: acb_autoComplete8에 ds_shipmentIndicationOrder 데이터 바인딩
};

scwin.f_setOrderInfoToUI = function() {
    // TODO: dma_orderInfo의 데이터를 화면 컴포넌트에 반영
};

scwin.f_selectTabMenu = async function(idx) {
    if ($c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
        scwin.hid_odrNo = scwin.hid_mcomOdrNo;
    }
    if ($c.gus.cfIsNull(scwin.hid_clntNo.trim())) {
        scwin.hid_clntNo = (scwin.params != null && scwin.params["clntNo"] != null) ? scwin.params["clntNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrKndCd.trim())) {
        scwin.hid_mchtOdrKndCd = (scwin.params != null && scwin.params["mchtOdrKndCd"] != null) ? scwin.params["mchtOdrKndCd"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrNo.trim())) {
        scwin.hid_mchtOdrNo = (scwin.params != null && scwin.params["mchtOdrNo"] != null) ? scwin.params["mchtOdrNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_mcomOdrNo.trim())) {
        scwin.hid_mcomOdrNo = (scwin.params != null && scwin.params["mcomOdrNo"] != null) ? scwin.params["mcomOdrNo"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_logSeq.trim())) {
        scwin.hid_logSeq = (scwin.params != null && scwin.params["logSeq"] != null) ? scwin.params["logSeq"] : "";
    }
    if ($c.gus.cfIsNull(scwin.hid_chkReterieve.trim())) {
        scwin.hid_chkReterieve = (scwin.params != null && scwin.params["type"] != null) ? scwin.params["type"] : "";
    }

    if ($c.gus.cfIsNull(idx)) {
        idx = 0;
    }
    if (idx > 1) {
        await $c.win.alert("현재개발중입니다.");
    }

    switch (idx) {
        case 0:
            if (!$c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
                if (scwin.hid_chkReterieve.trim() == "retrieve") {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                } else {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                }
            } else if (!$c.gus.cfIsNull(scwin.hid_clntNo.trim()) && !$c.gus.cfIsNull(scwin.hid_mchtOdrKndCd.trim()) && !$c.gus.cfIsNull(scwin.hid_mchtOdrNo.trim())) {
                scwin.f_setFrameOrderSearchQueryCondition();

                if (scwin.hid_chkReterieve.trim() == "retrieve") {
                    dma_search.set("repClntNo", scwin.hid_repClntNo);
                    dma_search.set("clntNo", scwin.hid_clntNo);
                    dma_search.set("clntNm", scwin.hid_clntNm);
                    dma_search.set("mchtOdrKndCd", scwin.hid_mchtOdrKndCd);
                    dma_search.set("mchtOdrNo", scwin.hid_mchtOdrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                } else {
                    dma_search.set("repClntNo", scwin.hid_repClntNo);
                    dma_search.set("clntNo", scwin.hid_clntNo);
                    dma_search.set("clntNm", scwin.hid_clntNm);
                    dma_search.set("mchtOdrKndCd", scwin.hid_mchtOdrKndCd);
                    dma_search.set("mchtOdrNo", scwin.hid_mchtOdrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                }
            }

            if (ds_mchtOdrKndCd.getRowCount() > 0) {
                scwin.f_setMchtOdrKndCombo();
            } else {
                ds_mchtOdrKndCd.insertRow(0);
                ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
                ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.hid_mchtOdrKndNm);
            }

            if (ds_shipmentIndicationOrder.getRowCount() > 0) {
                scwin.f_setLogSeqCombo();
            }
            break;
        case 1:
            if (!$c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
                if (scwin.hid_chkReterieve.trim() == "retrieve") {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                } else {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                }
            }
            break;
        case 2:
            if (!$c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
                if (scwin.hid_chkReterieve.trim() == "retrieve") {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                } else {
                    dma_search.set("mcomOdrNo", scwin.hid_odrNo);
                    await $c.sbm.execute(sbm_Retrieve);
                }
            }
            break;
    }
};

scwin.f_TabMenuUpdate = function(strUrl, strTitle) {
    if (strUrl != "" && strTitle != "") {
        $c.win.openMenu(strTitle, strUrl, "");
    }
};

scwin.f_setFrameOrderSearchQueryCondition = function() {
    dma_orderInfo.set("ctrtRepClntNo", scwin.hid_repClntNo);
    dma_orderInfo.set("clntNo", scwin.hid_clntNo);
    dma_orderInfo.set("clntNm", scwin.hid_clntNm);

    if (!$c.gus.cfIsNull(scwin.hid_mchtOdrKndCd) && scwin.hid_chkReterieve == "retrieve") {
        if (scwin.hid_chkReterieve != "retrieveIn") {
            dma_search.set("mchtOdrKndCd", scwin.hid_mchtOdrKndCd);
        }

        if (ds_mchtOdrKndCd.getRowCount() > 0) {
            scwin.f_setMchtOdrKndCombo();
        } else {
            ds_mchtOdrKndCd.insertRow(0);
            ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
            ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.hid_mchtOdrKndNm);
        }
    } else {
        // TODO: acb_autoComplete1 첫번째 항목 선택
    }

    dma_search.set("mchtOdrNo", scwin.hid_mchtOdrNo);
    dma_search.set("mcomOdrNo", scwin.hid_mcomOdrNo);
};

scwin.f_TabFrameResize = function(frameId, strHeight) {
    // TODO: WebSquare에서는 iframe 기반 탭이 아니므로 레이아웃 자동 조정
};

scwin.f_chgWrkPath = async function(mcomOdrNo) {
    if (mcomOdrNo == "") {
        await $c.win.alert("오더번호를 입력하십시오");
        return;
    }
    let param = {
        odrNo: mcomOdrNo,
        type: "retrieve"
    };
    $c.win.openMenu("작업경로", "/ui/tn/sd/odrmgnt/odrdtlinfo/tn_202_02_02b.xml", "tn_202_02_02b.xml", param);
};

scwin.f_CtrtTransTrfList = async function(ctrtNo) {
    if (ctrtNo == null || ctrtNo == "") {
        await $c.win.alert("계약번호가 없습니다.");
        return;
    }
    let param = {
        ctrtNo: ctrtNo
    };
    $c.win.openMenu("계약요율", "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_10b.xml", "tn_201_02_10b.xml", param);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    dma_search.undo();
    ed_input1.setValue("");
    ed_input2.setValue("");
    scwin.hid_odrNo = "";
    scwin.hid_repClntNo = "";
    scwin.hid_clntNo = "";
    scwin.hid_clntNm = "";
    scwin.hid_mchtOdrKndCd = "";
    scwin.hid_mchtOdrKndNm = "";
    scwin.hid_mchtOdrNo = "";
    scwin.hid_mcomOdrNo = "";
    scwin.hid_logSeq = "";
    scwin.hid_chkReterieve = "";
};

scwin.btn_edit_onclick = function(e) {
    // TODO: 수정 모드 전환 로직
};

scwin.btn_save_onclick = async function(e) {
    await $c.sbm.execute(sbm_Save);
};

scwin.sbm_Save_submitdone = async function(e) {
    if (ds_ResultMsg.getRowCount() > 0) {
        let resultMsg = ds_ResultMsg.getCellData(0, "resultMsg");
        await $c.win.alert(resultMsg);
        scwin.f_Retrieve();
    }
};

scwin.sbm_Save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_del_onclick = async function(e) {
    let chk = await $c.win.confirm("삭제하시겠습니까?");
    if (chk) {
        await $c.sbm.execute(sbm_Delete);
    }
};

scwin.sbm_Delete_submitdone = async function(e) {
    if (ds_ResultMsg.getRowCount() > 0) {
        let resultMsg = ds_ResultMsg.getCellData(0, "resultMsg");
        await $c.win.alert(resultMsg);
    }
};

scwin.sbm_Delete_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_trigger1_onclick = async function(e) {
    await $c.sbm.execute(sbm_SaveCommodity);
};

scwin.sbm_SaveCommodity_submitdone = async function(e) {
    if (ds_ResultMsg.getRowCount() > 0) {
        let resultMsg = ds_ResultMsg.getCellData(0, "resultMsg");
        await $c.win.alert(resultMsg);
        scwin.f_Retrieve();
    }
};

scwin.sbm_SaveCommodity_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_trigger2_onclick = function(e) {
    let mcomOdrNo = dma_orderInfo.get("mcomOdrNo");
    if ($c.gus.cfIsNull(mcomOdrNo)) {
        mcomOdrNo = scwin.hid_mcomOdrNo;
    }
    // TODO: 오더 Sheet 발행 로직
};

scwin.btn_trigger3_onclick = function(e) {
    let mcomOdrNo = dma_orderInfo.get("mcomOdrNo");
    if ($c.gus.cfIsNull(mcomOdrNo)) {
        mcomOdrNo = scwin.hid_mcomOdrNo;
    }
    scwin.f_chgWrkPath(mcomOdrNo);
};

scwin.btn_trigger4_onclick = function(e) {
    let ctrtNo = dma_orderInfo.get("ctrtNo");
    scwin.f_CtrtTransTrfList(ctrtNo);
};

scwin.sbm_reterieveMchtOdrKnd_submitdone = function(e) {
    if (ds_mchtOdrKndCd.getRowCount() > 0) {
        scwin.f_setMchtOdrKndCombo();
    } else {
        ds_mchtOdrKndCd.insertRow(0);
        ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
        ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.hid_mchtOdrKndNm);
        scwin.f_setMchtOdrKndCombo();
    }
};

scwin.sbm_reterieveMchtOdrKnd_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_addRow = function() {
    $c.data.insertRow(ds_commodityList);
};

scwin.f_deleteRow = function() {
    ds_commodityList.removeRow(ds_commodityList.getRowPosition());
};
